import React, { useState, useEffect } from 'react';
import { Users, ThumbsUp, ThumbsDown, UserPlus, Plus, MapPin, Check } from 'lucide-react';
import { supabase } from '../../services/supabaseClient';

// Kart-komponenter
import { MapContainer, TileLayer, Marker, Popup, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Fix för Leaflet-ikoner
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';
let DefaultIcon = L.icon({
    iconUrl: icon,
    shadowUrl: iconShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41]
});
L.Marker.prototype.options.icon = DefaultIcon;

// --- NYTT: En hjälpkomponent som lyssnar på klick på kartan ---
function MapClickHandler({ onMapClick }) {
  useMapEvents({
    click: (e) => {
      onMapClick(e.latlng); // Skickar koordinaterna uppåt när man klickar
    },
  });
  return null;
}

function ConvoyView() {
  const [proposals, setProposals] = useState([]);
  const [showInviteModal, setShowInviteModal] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);
  const [newPlaceName, setNewPlaceName] = useState('');

  // NYTT: Minne för koordinaterna vi klickat på
  const [selectedCoords, setSelectedCoords] = useState(null);

  const mapCenter = [67.4938, 18.3125];

  const fetchProposals = async () => {
    const { data, error } = await supabase
      .from('proposals')
      .select('*')
      .order('id', { ascending: true });
    if (!error) setProposals(data);
  };

  useEffect(() => {
    fetchProposals();
    const channel = supabase.channel('db-realtime').on('postgres_changes', 
      { event: '*', schema: 'public', table: 'proposals' }, () => fetchProposals()).subscribe();
    return () => supabase.removeChannel(channel);
  }, []);

  // Funktion när man klickar på kartan
  const handleMapClick = (latlng) => {
    setSelectedCoords(latlng);
    setShowAddModal(true); // Öppna rutan direkt när man valt plats!
  };

  const handleVote = async (id, type) => {
    const proposal = proposals.find(p => p.id === id);
    if (!proposal) return;
    const isUpvote = type === 'up';
    const newVotesUp = isUpvote ? proposal.votes_up + 1 : proposal.votes_up;
    const newVotesDown = !isUpvote ? proposal.votes_down + 1 : proposal.votes_down;

    await supabase.from('proposals').update({ 
      votes_up: newVotesUp, 
      votes_down: newVotesDown 
    }).eq('id', id);
  };

  const handleAddProposal = async () => {
    if (newPlaceName.trim() === '' || !selectedCoords) return;

    const fakeWeather = ['☀️ 22°C', '⛅ 19°C', '🌧️ 14°C'][Math.floor(Math.random() * 3)];

    const { error } = await supabase
      .from('proposals')
      .insert([{ 
        name: newPlaceName, 
        weather: fakeWeather, 
        votes_up: 0, 
        votes_down: 0,
        lat: selectedCoords.lat, // SPARA LATITUD
        lng: selectedCoords.lng  // SPARA LONGITUD
      }]);

    if (!error) {
      setShowAddModal(false);
      setNewPlaceName('');
      setSelectedCoords(null);
    }
  };

  return (
    <div style={{ padding: '20px' }} className="animate-fade-in">

      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h1 style={{ fontSize: '24px', fontWeight: 'bold', color: '#2D5A27', margin: 0, display: 'flex', alignItems: 'center', gap: '10px' }}>
          <Users size={28} /> Min Konvoj
        </h1>
        <button onClick={() => setShowInviteModal(true)} style={inviteBtnStyle}>
          <UserPlus size={16} /> Bjud in
        </button>
      </header>

      {/* KARTAN */}
      <div style={mapWrapperStyle}>
        <MapContainer center={mapCenter} zoom={11} style={{ height: '100%', width: '100%' }}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" attribution='&copy; OSM' />

          {/* Lyssnaren för klick */}
          <MapClickHandler onMapClick={handleMapClick} />

          {/* Rita ut alla nålar från DB */}
          {proposals.map((prop) => (
            prop.lat && prop.lng && (
              <Marker key={prop.id} position={[prop.lat, prop.lng]}>
                <Popup>
                  <div style={{ textAlign: 'center' }}>
                    <strong>{prop.name}</strong><br />
                    👍 {prop.votes_up}
                  </div>
                </Popup>
              </Marker>
            )
          ))}

          {/* Visa en tillfällig nål där man klickat */}
          {selectedCoords && (
            <Marker position={[selectedCoords.lat, selectedCoords.lng]} opacity={0.6} />
          )}
        </MapContainer>
      </div>

      <h2 style={{ fontSize: '18px', marginBottom: '15px' }}>Omröstning: Nattplats</h2>
      <p style={{ fontSize: '12px', color: '#95A5A6', marginBottom: '15px' }}>💡 Klicka på kartan för att välja en ny plats!</p>

      <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
        {proposals.map((prop) => (
          <div key={prop.id} style={proposalCardStyle}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
              <span style={{ fontWeight: 'bold' }}>{prop.name}</span>
              <span style={weatherBadgeStyle}>{prop.weather}</span>
            </div>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button onClick={() => handleVote(prop.id, 'up')} style={voteBtnStyle(true)}>
                <ThumbsUp size={18} /> {prop.votes_up}
              </button>
              <button onClick={() => handleVote(prop.id, 'down')} style={voteBtnStyle(false)}>
                <ThumbsDown size={18} /> {prop.votes_down}
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* MODAL: LÄGG TILL PLATS */}
      {showAddModal && (
        <div style={overlayStyle} className="animate-fade-in">
          <div style={modalStyle}>
            <div style={{ textAlign: 'center', marginBottom: '15px' }}>
                <div style={iconCircleStyle}><MapPin size={32} color="#2D5A27" /></div>
            </div>
            <h2 style={{ textAlign: 'center', color: '#2D5A27' }}>Spara plats</h2>

            <div style={coordsBadgeStyle}>
               <Check size={14} /> Position vald på kartan
            </div>

            <input 
              type="text" 
              placeholder="Vad ska platsen kallas?" 
              value={newPlaceName}
              onChange={(e) => setNewPlaceName(e.target.value)}
              style={inputStyle}
              autoFocus
            />

            <button onClick={handleAddProposal} style={primaryBtnStyle}>Lägg till i omröstningen</button>
            <button onClick={() => { setShowAddModal(false); setSelectedCoords(null); }} style={cancelBtnStyle}>Avbryt</button>
          </div>
        </div>
      )}

      {/* MODAL: BJUD IN (Kortad för tydlighet) */}
      {showInviteModal && (
        <div style={overlayStyle} className="animate-fade-in">
          <div style={modalStyle}>
            <h2 style={{ textAlign: 'center', color: '#2D5A27' }}>Konvoj-kod</h2>
            <div style={codeBoxStyle}>CAMP-84X</div>
            <button onClick={() => setShowInviteModal(false)} style={primaryBtnStyle}>Klar</button>
          </div>
        </div>
      )}
    </div>
  );
}

